// A single interface
abstract class Shape {
  double area();
}

// Many implementations
class Circle extends Shape {
  final double r;
  Circle(this.r);
  @override double area() => 3.14159 * r * r;
}

class Square extends Shape {
  final double s;
  Square(this.s);
  @override double area() => s * s;
}

// One function works on ALL shapes — present AND future
double totalArea(List<Shape> shapes) {
  double total = 0;
  for (final s in shapes) total += s.area();     // polymorphic call!
  return total;
}

void main() {
  print(totalArea([Circle(5), Square(3), Circle(2)])); // 100.53125
  // If tomorrow you add a Triangle, totalArea() doesn't change.
  // THAT is the win — 'open for extension, closed for modification.'
}

// Overriding (Dart & every OOP language):
class Animal { void speak() => print('...'); }
class Dog extends Animal {
  @override void speak() => print('Woof!');      // REDEFINES
}
final a = Dog();
a.speak();  // Woof! — runtime dispatch to Dog's version

