// File: oop_demo.dart
// Run: dart oop_demo.dart
abstract class PaymentMethod {                    // ABSTRACTION
  bool pay(double amount);
  String get displayName;
}

class CreditCard extends PaymentMethod {
  final String _number;                           // ENCAPSULATION
  double _availableCredit;

  CreditCard(this._number, this._availableCredit);

  @override String get displayName =>              // POLYMORPHISM
      'Card ending ${_number.substring(_number.length - 4)}';

  @override bool pay(double amount) {
    if (amount > _availableCredit) return false;
    _availableCredit -= amount;
    return true;
  }
}

class Wallet extends PaymentMethod {              // INHERITANCE
  double _balance;
  Wallet(this._balance);
  @override String get displayName => 'Wallet';
  @override bool pay(double amount) {
    if (amount > _balance) return false;
    _balance -= amount;
    return true;
  }
}

class UPI extends PaymentMethod {
  final String _vpa;
  UPI(this._vpa);
  @override String get displayName => 'UPI ($_vpa)';
  @override bool pay(double amount) => true;      // assume server-side ok
}

// Client code doesn't know or care which one is being used:
void checkout(double amount, PaymentMethod method) {
  print('Charging ₹$amount via ${method.displayName}...');
  print(method.pay(amount) ? '  ✅ Paid' : '  ❌ Insufficient');
}

void main() {
  final methods = <PaymentMethod>[
    CreditCard('4111111111111234', 500),
    Wallet(1200),
    UPI('ada@bank'),
  ];
  for (final m in methods) checkout(299, m);
  print('');
  checkout(999, methods[0]);  // credit card — insufficient (only ₹201 left)
}

// Output:
// Charging ₹299 via Card ending 1234...
//   ✅ Paid
// Charging ₹299 via Wallet...
//   ✅ Paid
// Charging ₹299 via UPI (ada@bank)...
//   ✅ Paid
// 
// Charging ₹999 via Card ending 1234...
//   ❌ Insufficient
//
// Notice: `checkout()` doesn't know or care WHICH payment method.
// Adding a new type (e.g. NetBanking) requires ZERO changes to checkout().
// THAT is polymorphism paying off.
